"""pathops.operations — boolean path operations using op() from _pathops."""

from pathops._pathops import PathOp, op, Path, OpBuilder


def union(contours, outpen, fix_winding=True, keep_starting_points=True):
    """Compute union of multiple contours."""
    if len(contours) < 2:
        for c in contours:
            outpen.addComponent(c, (1, 0, 0, 1, 0, 0))
        return
    return _boolean_operation(PathOp.UNION, contours, outpen,
                              fix_winding, keep_starting_points)


def difference(subject, clip, outpen, fix_winding=True, keep_starting_points=True):
    """Compute difference (subject - clip)."""
    return _boolean_operation(PathOp.DIFFERENCE, [subject, clip], outpen,
                              fix_winding, keep_starting_points)


def intersection(subject, clip, outpen, fix_winding=True, keep_starting_points=True):
    """Compute intersection of subject and clip."""
    return _boolean_operation(PathOp.INTERSECTION, [subject, clip], outpen,
                              fix_winding, keep_starting_points)


def xor(subject, clip, outpen, fix_winding=True, keep_starting_points=True):
    """Compute symmetric difference (XOR) of subject and clip."""
    return _boolean_operation(PathOp.XOR, [subject, clip], outpen,
                              fix_winding, keep_starting_points)


def _boolean_operation(operation, contours, outpen, fix_winding=True,
                       keep_starting_points=True):
    """Generic boolean operation on path contours using OpBuilder."""
    try:
        builder = OpBuilder(fix_winding=fix_winding,
                           keep_starting_points=keep_starting_points)
        for contour in contours:
            builder.add(contour, operation)
        result = builder.resolve()
        result.replay(outpen)
    except Exception:
        # Fallback: just replay first contour
        if contours:
            try:
                contours[0].replay(outpen)
            except Exception:
                pass
